area__bubble--user': msg.role === 'user', 'chat-area__bubble--ai': msg.role === 'assistant' }\"\n      >\n        <div class=\"chat-area__bubble-role\">\n          <i :class=\"msg.role === 'user' ? 'fa-solid fa-user' : 'fa-solid fa-robot'\" />\n        </div>\n        <div class=\"chat-area__bubble-content\">{{ msg.content }}</div>\n      </div>\n\n      <div v-if=\"store.isLoading\" class=\"chat-area__loading\">\n        <i class=\"fa-solid fa-spinner fa-spin\" />\n        <span>AI 正在生成...</span>\n      </div>\n    </div>\n\n    <!-- 快捷操作 -->\n    <div class=\"chat-area__shortcuts\">\n      <button class=\"chat-area__shortcut-btn\" @click=\"store.autoGenerateFromPreset()\" title=\"从预设扫描\">\n        <i class=\"fa-solid fa-magnifying-glass\" />\n        从预设扫描\n      </button>\n      <button class=\"chat-area__shortcut-btn\" @click=\"store.clearChat()\" title=\"清空对话\">\n        <i class=\"fa-solid fa-trash-can\" />\n      </button>\n    </div>\n\n    <!-- 输入区 -->\n    <div class=\"chat-area__input-row\">\n      <input\n        v-model=\"inputText\"\n        class=\"chat-area__input\"\n        placeholder=\"描述你想要的面板...\"\n        :disabled=\"store.isLoading\"\n        @keydown.enter.prevent=\"handleSend\"\n      />\n      <button\n        class=\"chat-area__send-btn\"\n        :disabled=\"!inputText.trim() || store.isLoading\"\n        @click=\"handleSend\"\n      >\n        <i class=\"fa-solid fa-paper-plane\" />\n      </button>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { useStore } from './store';\n\nconst store = useStore();\nconst inputText = ref('');\nconst messagesRef = ref<HTMLElement>();\n\nasync function handleSend() {\n  const text = inputText.value.trim();\n  if (!text || store.isLoading) return;\n\n  inputText.value = '';\n  await store.sendChat(text);\n\n  // 滚动到底部\n  await nextTick();\n  if (messagesRef.value) {\n    messagesRef.value.scrollTop = messagesRef.value.scrollHeight;\n  }\n}\n\n// 自动滚动\nwatch(\n  () => store.chatHistory.length,\n  async () => {\n    await nextTick();\n    if (messagesRef.value) {\n      messagesRef.value.scrollTop = messagesRef.value.scrollHeight;\n    }\n  },\n);\n</script>\n\n<style scoped>\n.chat-area {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n  min-width: 0;\n}\n\n.chat-area__messages {\n  flex: 1;\n  overflow-y: auto;\n  padding: 12px;\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n}\n\n.chat-area__empty {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  height: 100%;\n  color: rgba(255, 255, 255, 0.3);\n  text-align: center;\n  gap: 4px;\n}\n\n.chat-area__empty i {\n  font-size: 28px;\n  margin-bottom: 8px;\n}\n\n.chat-area__empty p {\n  margin: 0;\n  font-size: 13px;\n}\n\n.chat-area__hint {\n  font-size: 11px !important;\n  color: rgba(255, 255, 255, 0.2) !important;\n}\n\n/* --- Bubbles --- */\n.chat-area__bubble {\n  display: flex;\n  gap: 8px;\n  max-width: 95%;\n}\n\n.chat-area__bubble--user {\n  align-self: flex-end;\n  flex-direction: row-reverse;\n}\n\n.chat-area__bubble--ai {\n  align-self: flex-start;\n}\n\n.chat-area__bubble-role {\n  width: 26px;\n  height: 26px;\n  border-radius: 50%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 12px;\n  flex-shrink: 0;\n}\n\n.chat-area__bubble--user .chat-area__bubble-role {\n  background: rgba(100, 181, 246, 0.2);\n  color: #64b5f6;\n}\n\n.chat-area__bubble--ai .chat-area__bubble-role {\n  background: rgba(129, 199, 132, 0.2);\n  color: #81c784;\n}\n\n.chat-area__bubble-content {\n  padding: 8px 12px;\n  border-radius: 12px;\n  font-size: 12.5px;\n  line-height: 1.5;\n  white-space: pre-wrap;\n  word-break: break-word;\n}\n\n.chat-area__bubble--user .chat-area__bubble-content {\n  background: rgba(100, 181, 246, 0.12);\n  color: rgba(255, 255, 255, 0.9);\n  border-bottom-right-radius: 4px;\n}\n\n.chat-area__bubble--ai .chat-area__bubble-content {\n  background: rgba(255, 255, 255, 0.05);\n  color: rgba(255, 255, 255, 0.8);\n  border-bottom-left-radius: 4px;\n}\n\n.chat-area__loading {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 8px 12px;\n  color: rgba(255, 255, 255, 0.4);\n  font-size: 12px;\n}\n\n/* --- Shortcuts --- */\n.chat-area__shortcuts {\n  display: flex;\n  gap: 4px;\n  padding: 4px 12px;\n  border-top: 1px solid rgba(255, 255, 255, 0.06);\n}\n\n.chat-area__shortcut-btn {\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  padding: 4px 8px;\n  border: none;\n  background: rgba(255, 255, 255, 0.06);\n  color: rgba(255, 255, 255, 0.55);\n  border-radius: 4px;\n  font-size: 11px;\n  cursor: pointer;\n  transition: background 0.15s, color 0.15s;\n}\n\n.chat-area__shortcut-btn:hover {\n  background: rgba(255, 255, 255, 0.1);\n  color: rgba(255, 255, 255, 0.8);\n}\n\n/* --- Input --- */\n.chat-area__input-row {\n  display: flex;\n  gap: 6px;\n  padding: 8px 12px;\n  border-top: 1px solid rgba(255, 255, 255, 0.06);\n}\n\n.chat-area__input {\n  flex: 1;\n  padding: 8px 12px;\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  border-radius: 8px;\n  background: rgba(255, 255, 255, 0.04);\n  color: rgba(255, 255, 255, 0.9);\n  font-size: 13px;\n  outline: none;\n  transition: border-color 0.2s;\n}\n\n.chat-area__input:focus {\n  border-color: rgba(100, 181, 246, 0.4);\n}\n\n.chat-area__input::placeholder {\n  color: rgba(255, 255, 255, 0.25);\n}\n\n.chat-area__send-btn {\n  width: 36px;\n  height: 36px;\n  border: none;\n  border-radius: 8px;\n  background: rgba(100, 181, 246, 0.2);\n  color: #64b5f6;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transition: background 0.15s, transform 0.1s;\n}\n\n.chat-area__send-btn:hover:not(:disabled) {\n  background: rgba(100, 181, 246, 0.35);\n  transform: scale(1.05);\n}\n\n.chat-area__send-btn:disabled {\n  opacity: 0.35;\n  cursor: not-allowed;\n}\n</style>\n"],"sourceRoot":""}]);
